mapper.select:
SELECT s.*, COALESCE(repo.cnt, 0) AS repository_count, COALESCE(kv.cnt, 0) AS knowledge_version_count, repo.last_decompile_at AS last_decompile_at FROM ci_system s LEFT JOIN ( SELECT system_id, COUNT(*) AS cnt, MAX(last_decompile_at) AS last_decompile_at FROM ci_repository WHERE deleted_at IS NULL GROUP BY system_id ) repo ON repo.system_id = s.id LEFT JOIN ( SELECT system_id, COUNT(*) AS cnt FROM ci_knowledge_version GROUP BY system_id ) kv ON kv.system_id = s.id
s.deleted_at IS NULL
AND s.name LIKE '%' || #{name,jdbcType=VARCHAR} || '%'
AND s.owner = #{owner}
AND s.state = #{state}
AND s.status = #{status}
ORDER BY s.created_at DESC
